mapper.select:
SELECT id, parent_id, name, description, created_at
FROM categories
WHERE id = #{id}

WITH RECURSIVE category_tree AS ( -- 루트 카테고리 SELECT id, parent_id, name, description, created_at, 1 AS level FROM categories WHERE id = #{rootId}
UNION ALL
-- 자식 카테고리 SELECT c.id, c.parent_id, c.name, c.description, c.created_at, ct.level + 1 FROM categories c INNER JOIN category_tree ct ON c.parent_id = ct.id ) SELECT id, parent_id, name, description, created_at FROM category_tree ORDER BY level, id

WITH RECURSIVE descendants AS ( -- 시작 카테고리 SELECT id, parent_id, name, description, created_at FROM categories WHERE parent_id = #{parentId}
UNION ALL
-- 재귀적으로 자식 조회 SELECT c.id, c.parent_id, c.name, c.description, c.created_at FROM categories c INNER JOIN descendants d ON c.parent_id = d.id ) SELECT id, parent_id, name, description, created_at FROM descendants ORDER BY id
